def get_job(job_id: str) -> Dict[str, Any]:
    """Get job from memory, falling back to disk (survives server restarts)."""
    if job_id in JOBS:
        return JOBS[job_id]

    # Try disk fallback
    job_path = JOBS_DIR / f"{job_id}.json"
    if job_path.exists():
        data = load_json(job_path)
        if data:
            JOBS[job_id] = data
            return data

    return {"status": "not_found"}


