@router.post("/style-transfer/batch")
def style_transfer_batch(
    image: UploadFile = File(...),
    extra_prompt: str = Form(default="")
):
    if not image.content_type or not image.content_type.startswith("image/"):
        raise HTTPException(status_code=400, detail="Uploaded file must be an image")

    extension = os.path.splitext(image.filename or "")[1] or ".png"
    input_file_name = f"upload_{uuid4().hex}{extension}"
    input_path = os.path.join("outputs", input_file_name)

    try:
        with open(input_path, "wb") as buffer:
            shutil.copyfileobj(image.file, buffer)
        outputs = []
        for style_name in STYLE_PROMPTS:
            styled_path = stylize_image(input_path=input_path, style=style_name, extra_prompt=extra_prompt)
            outputs.append(
                {
                    "style": style_name,
                    "styled_image_url": f"/outputs/{os.path.basename(styled_path)}",
                    "styled_image_path": styled_path,
                }
            )
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"Batch style transfer failed: {exc}") from exc
    finally:
        image.file.close()

    response_payload = {
        "input_image_url": f"/outputs/{os.path.basename(input_path)}",
        "outputs": outputs,
    }
    append_history(
        {
            "type": "img2img-batch",
            "style": "all",
            "input_image_url": response_payload["input_image_url"],
            "outputs": [{"style": item["style"], "url": item["styled_image_url"]} for item in outputs],
        }
    )

    return response_payload


