                sentiment = 0.0

            return {
                "sentiment_score": max(-1.0, min(1.0, sentiment)),
                "confidence": score,
                "emotion": emotion
            }
        except Exception as e:
            print(f"[SentimentAnalyzer] Error: {e}")
            return self._fallback_sentiment(text)

    def _fallback_sentiment(self, text: str) -> Dict[str, float]:
        """Fallback to keyword-based sentiment"""
        t = (text or "").lower()
        pos_words = ["good", "great", "excellent", "happy", "thanks", "helpful", "perfect"]
        neg_words = ["angry", "frustrat", "hate", "sucks", "cancel", "refund", "useless", "terrible"]

        pos_count = sum(1 for w in pos_words if w in t)
        neg_count = sum(1 for w in neg_words if w in t)

        if neg_count > pos_count:
            sentiment = -0.5 - (neg_count * 0.1)
        elif pos_count > neg_count:
            sentiment = 0.5 + (pos_count * 0.1)
        else:
            sentiment = 0.0

        return {
            "sentiment_score": max(-1.0, min(1.0, sentiment)),
            "confidence": 0.5,
            "emotion": "neutral"
        }

