# =============== Persona detection ===============
TECH_KEYWORDS = ["debug", "stack trace", "error", "exception", "api", "endpoint", "response code", "log", "version", "install"]
FRUSTRATED_KEYWORDS = ["angry", "frustrat", "sick of", "not working", "crash", "annoy", "hate", "cancel", "refund"]
BUSINESS_KEYWORDS = ["report", "meeting", "client", "stakeholder", "sla", "pricing", "cost", "budget", "enterprise"]

def detect_persona(text: str) -> str:
    t = (text or "").lower()
    score = {"technical_expert": 0, "frustrated_user": 0, "business_exec": 0, "general_user": 0}
    for w in TECH_KEYWORDS:
        if w in t:
            score["technical_expert"] += 1
    for w in FRUSTRATED_KEYWORDS:
        if w in t:
            score["frustrated_user"] += 1
    for w in BUSINESS_KEYWORDS:
        if w in t:
            score["business_exec"] += 1
    if re.search(r"!{1,}", text or ""):
        score["frustrated_user"] += 1
    if t.isupper() and len(t) > 3:
        score["frustrated_user"] += 1
    persona = max(score, key=score.get)
    return "general_user" if score[persona] == 0 else persona

# =============== KB Retriever ===============
class KBRetriever:
    def __init__(self, kb: List[Dict]):
        self.kb = kb
        self.titles = [entry["title"] + "\n" + entry["content"] for entry in kb]
        if HAS_SENTENCE_TRANSFORMERS:
            try:
                self.model = SentenceTransformer('all-MiniLM-L6-v2')
                self.embeddings = self.model.encode(self.titles, convert_to_tensor=True)
                self.method = 'sbert'
            except Exception:
                self.method = 'tfidf'
        elif HAS_SKLEARN:
            self.vectorizer = TfidfVectorizer()
            self.tfidf_matrix = self.vectorizer.fit_transform(self.titles)
            self.method = 'tfidf'
        else:
            self.method = 'keyword'

    def retrieve(self, query: str, top_k: int = 1) -> Tuple[List[Dict], float]:
        if self.method == 'sbert':
            q_emb = self.model.encode(query, convert_to_tensor=True)
            scores = util.pytorch_cos_sim(q_emb, self.embeddings)[0]
            top_idx = int(scores.argmax())
            conf = float(scores.max())
            return [self.kb[top_idx]], conf
        elif self.method == 'tfidf':
            q_vec = self.vectorizer.transform([query])
            sims = cosine_similarity(q_vec, self.tfidf_matrix)[0]
            top_idx = int(sims.argmax())

            conf = float(sims.max())
            return [self.kb[top_idx]], conf
        else:
            q = (query or "").lower()
            best = None
            best_score = 0
            for entry in self.kb:
                text = (entry['title'] + ' ' + entry['content']).lower()
                common = sum(1 for w in set(re.findall(r"\w+", q)) if w in text)
                if common > best_score:
                    best_score = common
                    best = entry
            conf = min(1.0, best_score / 5.0) if best_score > 0 else 0.0
            return ([best] if best else []), conf

# =============== Ollama HTTP call ===============
def call_ollama_http(prompt: str, model: str = OLLAMA_MODEL, timeout: int = OLLAMA_HTTP_TIMEOUT) -> str:
    """
    Call Ollama via HTTP endpoint. Expected JSON: { "model": "...", "prompt": "...", ... }
    Implementation may need minor changes depending on your Ollama version.
    """
    payload = {
        "model": model,
        "prompt": prompt,
        "stream": False
    }
    try:
        resp = requests.post(OLLAMA_BASE_URL, json=payload, timeout=timeout)
        resp.raise_for_status()
        data = resp.json()
        # try common shapes
        if isinstance(data, dict):
            if "response" in data:
                return str(data["response"])
            if "choices" in data and len(data["choices"]) > 0:
                return data["choices"][0].get("text", "") or str(data["choices"][0])
            if "output" in data:
                if isinstance(data["output"], list):
                    return " ".join(map(str, data["output"]))
                return str(data["output"])
        return resp.text
    except Exception as e:
        # fallback: try CLI if available
        OLLAMA_CLI = shutil.which("ollama")
        if OLLAMA_CLI:
            try:
                cmd = [OLLAMA_CLI, "generate", model, "--prompt", prompt]
                proc = subprocess.run(cmd, capture_output=True, text=True, timeout=30)
                if proc.returncode == 0:
                    return proc.stdout.strip()

            except Exception:
                pass
        return f"[LLM unavailable: {e}]"

