NEGATIVE_WORDS = ["angry", "frustrat", "hate", "sucks", "cancel", "refund", "useless"]
def sentiment_score(text: str) -> float:
    """Get sentiment score using Hugging Face model or fallback"""
    if sentiment_analyzer and sentiment_analyzer.model:
        result = sentiment_analyzer.analyze(text)
        return result.get("sentiment_score", 0.0)
    else:
        # Fallback to keyword-based
        t = (text or "").lower()
        neg = sum(1 for w in NEGATIVE_WORDS if w in t)
        if re.search(r"!", text or ""):
            neg += 1
        score = (0 - neg) / (1 + neg)
        return max(-1.0, min(1.0, score))

def should_escalate(user_message: str, kb_confidence: float, persona: str, history: List[Tuple[str, str]]) -> Tuple[bool, str]:
    s = sentiment_score(user_message)
    if s < -0.3:
        return True, "negative_sentiment"
    if kb_confidence < 0.2:
        return True, "low_kb_confidence"
    unresolved_turns = sum(1 for u, a in history if "I'll escalate" in a or a.startswith("Here's"))
    if unresolved_turns >= 3:
        return True, "multiple_unresolved_turns"

    if persona == "business_exec" and kb_confidence < 0.8:
        return True, "business_prefers_human"
    return False, ""

# =============== Handoff formatting, JSON & PDF ===============
def format_handoff(user_message: str, persona: str, history: List[Tuple[str, str]], reason: str, ticket_link: Optional[str] = None) -> str:
    summary_lines = [
        f"Persona: {persona}",
        f"Escalation reason: {reason}",
        "Conversation history (last 10 turns):"
    ]
    for u, a in history[-10:]:
        summary_lines.append(f"User: {u}")
        summary_lines.append(f"Agent: {a}")
    summary_lines.append(f"Latest user message: {user_message}")
    if ticket_link:
        summary_lines.append(f"Ticket link: {ticket_link}")
    return "\n".join(summary_lines)

def save_escalation_json(handoff_text: str, persona: str) -> str:
    data = {"timestamp": time.strftime("%Y-%m-%d %H:%M:%S"), "persona": persona, "summary": handoff_text}
    filename = f"escalation_{int(time.time())}_{uuid.uuid4().hex[:6]}.json"
    filepath = _export_path(filename)
    with open(filepath, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=2)
    return filepath

def create_escalation_pdf(summary: str, filename: str = "escalation_summary.pdf") -> Optional[str]:
    if not HAS_REPORTLAB:
        return None
    try:
        filepath = _export_path(filename)
        c = canvas.Canvas(filepath, pagesize=letter)
        textobject = c.beginText(40, 750)
        textobject.setFont("Helvetica", 10)
        for line in summary.splitlines():
            # wrap long lines
            if len(line) > 120:
                # simple wrap
                for i in range(0, len(line), 120):
                    textobject.textLine(line[i:i+120])
            else:
                textobject.textLine(line)
        c.drawText(textobject)
        c.save()
        return filepath
    except Exception as e:
        print(f"[PDF generation error] {e}")
        return None

