def run_distributed_training(config: dict, num_trials: int = 1):
    """
    Run training with Ray when available, otherwise local fallback.

    Args:
        config: Training configuration
        num_trials: Number of trials for hyperparameter search

    Returns:
        Ray tune analysis object, local best-trial dict, or metrics dict
    """
    if ray is None or tune is None:
        return _run_local_trials(config, num_trials=num_trials)

    if not ray.is_initialized():
        ray.init(ignore_reinit_error=True)

    if num_trials > 1:
        lr_values = config.get("lr", [config["lr"]])
        if not isinstance(lr_values, list):
            lr_values = [lr_values]

        analysis = tune.run(
            tune.with_parameters(train_with_ray),
            config={**config, "lr": tune.grid_search(lr_values[:num_trials])},
            num_samples=1,
            resources_per_trial={
                "cpu": config.get("num_cpus", 1),
                "gpu": config.get("num_gpus", 0),
            },
        )
        return analysis

    run_config = dict(config)
    if isinstance(run_config.get("lr"), list):
        run_config["lr"] = run_config["lr"][0]
    return ray.get(ray.remote(train_with_ray).remote(run_config))

